public class StaticChain {
    static int x = 5;
    static void setX(int val) { x = val; }
    static int getDouble() { return x * 2; }
    public static void main(String[] args) {
        System.out.println(getDouble());
        setX(10);
        System.out.println(getDouble());
        setX(getDouble() - 3);
        System.out.println(x);
    }
}
